void MRFTWIMarkingDlg::Build()
{
	pLabelRefSurf = new CATDlgLabel(_pMainFrame, (const char*)"Reference_Surface", 0 | CATDlgLabLeft);
	pLabelRefSurf->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	pSelectorListRefSurf = new CATDlgSelectorList(_pMainFrame, (const char*)"Ref Surface Selector	", 0);
	pSelectorListRefSurf->SetGridConstraints(0, 1, 4, 1, CATGRID_4SIDES);
	pSelectorListRefSurf->SetVisibleTextHeight(1);
	pSelectorListRefSurf->SetVisibleTextWidth(25);
	pSelectorListRefSurf->SetLine("No Surface Selected");
	
	pLabelRefPlane = new CATDlgLabel(_pMainFrame, (const char*)"Segment_Cutting_Plane", 0 | CATDlgLabLeft);
	pLabelRefPlane->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

	pSelectorListRefPlane = new CATDlgSelectorList(_pMainFrame, (const char*)"Ref Surface Selector", 0);
	pSelectorListRefPlane->SetGridConstraints(1, 1, 4, 1, CATGRID_4SIDES);
	pSelectorListRefPlane->SetVisibleTextHeight(1);
	pSelectorListRefPlane->SetVisibleTextWidth(25);
	pSelectorListRefPlane->SetLine("No Plane Selected");


	pLabelProfileType = new CATDlgLabel(_pMainFrame, (const char*)"Profile_Type", 0 | CATDlgLabLeft);
	pLabelProfileType->SetGridConstraints(2, 0, 1, 1, CATGRID_4SIDES);

	pComboProfileType = new CATDlgCombo(_pMainFrame, (const char*)"TWIProfileList", 0 | CATDlgCmbDropDown);
	pComboProfileType->SetGridConstraints(2, 1, 4, 1, CATGRID_4SIDES);
	pComboProfileType->SetVisibleTextWidth(20);
	pComboProfileType->SetVisibleTextHeight(5);
	this->SetComboBoxValuesReadFromNLS();

	pLabelCurveRatio = new CATDlgLabel(_pMainFrame, (const char*)"Apex_Curve_Ratio", 0 | CATDlgLabLeft);
	pLabelCurveRatio->SetGridConstraints(3, 0, 1, 1, CATGRID_4SIDES);

	pSpinnerCurveRatio = new CATDlgSpinner(_pMainFrame, (const char*)"StartPosition", 0 | CATDlgSpnEntry);
	pSpinnerCurveRatio->SetGridConstraints(3, 1, 1, 1, CATGRID_4SIDES);
	pSpinnerCurveRatio->SetFormat("%2gmm");
	pSpinnerCurveRatio->SetRange(0.f, 1.f, 10.0f);
	pSpinnerCurveRatio->SetCurrentValue(0.f);

	pLabelPositionAngle = new CATDlgLabel(_pMainFrame, (const char*)"Position_Angle", 0 | CATDlgLabLeft);
	pLabelPositionAngle->SetGridConstraints(4, 0, 1, 1, CATGRID_4SIDES);

	pSpinnerPositionAngle = new CATDlgSpinner(_pMainFrame, (const char*)"Position Angle", 0 | CATDlgSpnEntry);
	pSpinnerPositionAngle->SetGridConstraints(4, 1, 1, 1, CATGRID_4SIDES);
	pSpinnerPositionAngle->SetFormat("%2gdeg");
	pSpinnerPositionAngle->SetRange(-360.f, 360.f, 720.f);
	pSpinnerPositionAngle->SetCurrentValue(0.f);
	
	pLabelOffsetDistance = new CATDlgLabel(_pMainFrame, (const char*)"Offset_Distance", 0 | CATDlgLabLeft);
	pLabelOffsetDistance->SetGridConstraints(5, 0, 1, 1, CATGRID_4SIDES);

	pSpinnerOffsetDistance = new CATDlgSpinner(_pMainFrame, (const char*)"Offset Distance", 0 | CATDlgSpnEntry);
	pSpinnerOffsetDistance->SetGridConstraints(5, 1, 1, 1, CATGRID_4SIDES);
	pSpinnerOffsetDistance->SetFormat("%2gmm");
	pSpinnerOffsetDistance->SetRange(0.f, 100000.f, 100000.0f);
	pSpinnerOffsetDistance->SetCurrentValue(0.f);
	
	pLabelPaddingAngle = new CATDlgLabel(_pMainFrame, (const char*)"Padding_Angle", 0 | CATDlgLabLeft);
	pLabelPaddingAngle->SetGridConstraints(6, 0, 1, 1, CATGRID_4SIDES);

	pSpinnerPaddingAngle = new CATDlgSpinner(_pMainFrame, (const char*)"Padding Angle", 0 | CATDlgSpnEntry);
	pSpinnerPaddingAngle->SetGridConstraints(6, 1, 1, 1, CATGRID_4SIDES);
	pSpinnerPaddingAngle->SetFormat("%2gdeg");
	pSpinnerPaddingAngle->SetRange(-360.f, 360.f, 720.0f);
	pSpinnerPaddingAngle->SetCurrentValue(0.f);

	pLabelManufType = new CATDlgLabel(_pMainFrame, (const char*)"Manufacturing_Type", 0 | CATDlgLabLeft);
	pLabelManufType->SetGridConstraints(7, 0, 1, 1, CATGRID_4SIDES);

	pComboManufType = new CATDlgCombo(_pMainFrame, (const char*)"TWIMark ManufType", 0 | CATDlgCmbDropDown);
	pComboManufType->SetGridConstraints(7, 1, 4, 1, CATGRID_4SIDES);
	pComboManufType->SetVisibleTextWidth(20);
	pComboManufType->SetVisibleTextHeight(5);
	pComboManufType->SetLine("CNC");
	pComboManufType->SetLine("Additive");
}

void MRFTWIMarkingDlg::UpdateSelectorList(CATString strAction, CATUnicodeString aliasNameToSet)
{
	CATDlgSelectorList *pSelectorList = NULL;
	if (strAction == "TWIMarkSurface")
	{
		pSelectorList = pSelectorListRefSurf;
	}
	else if (strAction == "TWIMarkPlane")
	{
		pSelectorList = pSelectorListRefPlane;
	}

	pSelectorList->ClearLine();
	pSelectorList->SetLine(aliasNameToSet);

	int select = 0;
	pSelectorList->SetSelect(&select, 1);
}

void MRFTWIMarkingDlg::ClearOtherSelections(CATString strAction)
{
	if (strAction == "TWIMarkSurface")
	{
		pSelectorListRefPlane->ClearSelect();
		pComboProfileType->ClearSelect();
		pComboManufType->ClearSelect();
	}
	else if (strAction == "TWIMarkPlane")
	{
		pSelectorListRefSurf->ClearSelect();
		pComboProfileType->ClearSelect();
		pComboManufType->ClearSelect();
	}
	else if (strAction == "TWIMarkProfile")
	{
		pSelectorListRefSurf->ClearSelect();
		pSelectorListRefPlane->ClearSelect();
		pComboManufType->ClearSelect();
	}
	else if (strAction == "ManufacturingType")
	{
		pSelectorListRefSurf->ClearSelect();
		pSelectorListRefPlane->ClearSelect();
		pComboProfileType->ClearSelect();
	}
}

void MRFTWIMarkingDlg::GetValuesFromWidgets(double &curveRatio, double &PositionAngle, double &OffsetDistance, double &paddingAngle)
{
	curveRatio = (double)pSpinnerCurveRatio->GetCurrentValue();
	PositionAngle = (double)pSpinnerPositionAngle->GetCurrentValue();
	OffsetDistance = (double)pSpinnerOffsetDistance->GetCurrentValue();
	paddingAngle = (double)pSpinnerPaddingAngle->GetCurrentValue();
}

void MRFTWIMarkingDlg::SetValuesToWidgets(CATUnicodeString refSurface, CATUnicodeString refPlane, double curveRatio, 
	double PositionAngle, double OffsetDistance, double paddingAngle, int manufType, int profType)
{
	pSelectorListRefSurf->SetLine(refSurface, 0, CATDlgDataModify);
	pSelectorListRefPlane->SetLine(refPlane, 0, CATDlgDataModify);
	pSpinnerCurveRatio->SetCurrentValue((float)curveRatio);
	pSpinnerPositionAngle->SetCurrentValue((float)PositionAngle);
	pSpinnerOffsetDistance->SetCurrentValue((float)OffsetDistance);
	pSpinnerPaddingAngle->SetCurrentValue((float)paddingAngle);
	pComboManufType->SetSelect(manufType);
	pComboProfileType->SetSelect(profType);

}

void MRFTWIMarkingDlg::SetComboBoxValuesReadFromNLS()
{
	CATUnicodeString  profileCountAsStr;
	int profileCount;
	profileCountAsStr = CATMsgCatalog::BuildMessage("MRFTWIMarkingCmd", "MRFTWIMarkingCmd.ProfileCount");
	profileCountAsStr.ConvertToNum(&profileCount, "%d");

	CATUnicodeString UDFNameListLines[100], udfName;
	bool atleatOneProfileFound = false;

	for (int i = 1; i <= profileCount; i++)
	{
		CATUnicodeString profileName = "MRFTWIMarkingCmd.UDFName.Profile_";

		CATUnicodeString CountAsStr;
		CountAsStr.BuildFromNum(i);
		profileName.Append(CountAsStr);
		udfName = CATMsgCatalog::BuildMessage("MRFTWIMarkingCmd", profileName.ConvertToChar());
		if (!udfName.Compare(""))
		{
			UDFNameListLines[i - 1] = udfName;
			atleatOneProfileFound = true;
		}
	}

	/*for (int j = 0; j < profileCount; j++)
	{
		CATString sKey;
		CATUnicodeString usText;
		sprintf(bufferName_key, "MRFTWIMarkingCmd.UDFName.Profile_%d", j);
		sKey = bufferName_key;
		if (0 != _pMRFTWIMarkingDlg->GetResourceValueFromKey(sKey, usText))
		{
			UDFNameListLines[j] = usText;
			atleatOneProfileFound = true;
		}
	}*/

	if (atleatOneProfileFound)
		pComboProfileType->SetLine(UDFNameListLines, profileCount);
}
